mapper.select:
SELECT img_src AS nmAni FROM ani_tb WHERE ani = #{ani}
UNION ALL
SELECT img_src AS nmMbti FROM mbti_tb WHERE mbti = #{mbti}

mapper.insert:
BEGIN
    DELETE FROM elcaro.url_tb
    WHERE id = #{id}
      AND TRUNC(result_date) = TRUNC(SYSDATE);

    INSERT INTO elcaro.url_tb (
        seq,
        result_date,
        id,
        url
    ) VALUES (
        (SELECT NVL(MAX(seq), 0) + 1 FROM elcaro.url_tb),
        SYSDATE,
        #{id},
        #{url}
    );
END;
